/** 由 scripts/build/generate-bundled-config.mjs 根据 config/default.yaml 生成，请勿手改。 */
export const bundledDefaultConfigYaml = "agent:\n  id: \"ada-agent-local\"\n  mode: \"foreground\"\n  setupOnFirstRun: true\n\nbootstrapUI:\n  enabled: true\n  mode: \"auto\" # auto | cli | gui\n  host: \"127.0.0.1\"\n  port: 17650\n  autoOpenBrowser: true\n  sessionTtlSec: 600\n  secretsProvider: \"auto\" # auto | keychain | credman | file\n  native:\n    enabled: false\n    command: \"\" # e.g. ./bootstrap-ui / .\\bootstrap-ui.exe\n    args: []\n    timeoutMs: 120000\n    fallbackToWeb: true\n\ntransport:\n  mode: \"auto\"\n  streamProtocol: \"websocket\"\n  requestPath: \"/api/v1/execute\"\n  healthPath: \"/health\"\n  streamPath: \"/ws\"\n  requestTimeoutMs: 15000\n\ngraphics:\n  enabled: false\n  fallbackOnSemanticFailure: false\n  minConfidence: 0.8\n\nviewControl:\n  enabled: true\n  defaultControlMode: semantic\n  snapshot:\n    maxNodes: 500\n    includeScreenshot: true\n    cacheTtlMs: 3000\n  visual:\n    adapter: noop\n    requireRiskApproved: true\n  registry:\n    maxViewsPerSession: 200\n\n# MCP 工具返回体（Host / 大模型可见）\nmcp:\n  # false（默认）= 精简 result，省 token；true = 完整 CommandResult，便于人工调试\n  verboseResult: false\n  # extract 是否附带 rawResult（也可用 ADA_MCP_EXTRACT_RAW=1）\n  extractRaw: false\n  # JSON 是否 pretty-print（也可用 ADA_MCP_JSON_PRETTY=1）\n  jsonPretty: false\n\nmonitoring:\n  enabled: false\n  platforms: [\"web\"] # 可选子集；启用 Android/iOS/Harmony 时追加对应平台（doctor 与运行时检查据此判定）\n  sampleEvery: 1 # 每 N 条操作采样一次，1 表示全量\n  outputDir: \"artifacts/monitoring\"\n  onFailureOnly: false # true 时仅失败操作抓图，性能更优\n  groupBySession: true # 按 sessionId/requestId 分层归档\n  nonBlocking: true # true 时监控异步执行，不阻塞主链路\n  resolution:\n    maxWidth: 1280\n    maxHeight: 720\n    keepAspectRatio: true # 保持比例，避免监控图像变形\n\n# 移动设备：引导/启动后自动 adb/hdc/xcrun 扫描并写入 .ada-agent/devices.json\ndevices:\n  autoScanOnSetup: true\n  autoScanOnStart: true\n\nqueue:\n  inboxDir: \"tasks/inbox\"\n  processedDir: \"tasks/processed\"\n  failedDir: \"tasks/failed\"\n  pollIntervalMs: 3000\n  maxFileRetryAttempts: 2\n\n# Web / Playwright 默认：有头、窗口置前（测试/调试可见）；CI 可设 ADA_PLAYWRIGHT_HEADLESS=true\nplaywright:\n  headless: false\n  bringToFront: true\n\ndependencies:\n  autoInstallOnStart: true\n  playwrightBrowser: \"chromium\" # chromium | firefox | webkit | all\n  playwrightInstallTargets: [\"chromium\"] # chromium | chrome | msedge | firefox | webkit | all\n  playwrightDownloadHost: \"https://cdn.playwright.dev\"\n  # 国内 npm 镜像（按优先级；install-deps 启动时测速选最快，无需用户配置）\n  npmRegistryCandidates:\n    - \"https://registry.npmjs.org\" # 官方\n    - \"https://registry.npmmirror.com\" # 阿里云 / npmmirror\n    - \"https://mirrors.cloud.tencent.com/npm\" # 腾讯云\n    - \"https://mirrors.sjtug.sjtu.edu.cn/npm-registry\" # 上海交大\n    - \"https://npmreg.proxy.ustclug.org\" # 中科大\n    - \"https://repo.huaweicloud.com/repository/npm\" # 华为云\n  # 浏览器 zip CDN（按序测速，吞吐最高优先；同速时官方靠前）\n  playwrightHostCandidates:\n    - \"https://cdn.playwright.dev\"\n    - \"https://playwright.azureedge.net\"\n    - \"https://cdn.npmmirror.com/binaries/playwright\"\n    - \"https://npmmirror.com/mirrors/playwright\"\n  # 纯血鸿蒙工具（hdc 等），相对工作区根目录；也可用环境变量 ADA_TOOLS_DIR 覆盖\n  toolsDir: \"tools\"\n  # install-deps --only=harmony / --only=all 时自动下载 hdc（支持 .zip 或直链；GitHub blob 链接会自动转 raw）\n  harmonyHdcDownloadUrls:\n    - \"https://raw.githubusercontent.com/osgm/ada/main/tools/hdc.exe\"\n\n# 可选：命名 app profile（E2E / MCP 通过 ADA_APP_PROFILE 引用；勿在此内置业务 App）\n# appProfiles:\n#   example:\n#     harmony:\n#       appId: \"com.example.app\"\n#       abilityId: \"EntryAbility\"\n#     android:\n#       appId: \"com.example.app\"\n\n# 旧移动驱动配置段已弃用（driver-android / driver-ios / driver-harmony 直连通道）\n";
